export const meta = {
  name: 'qa-semantic-search',
  description: 'Semantic search for QA workflow',
  phases: [
    { title: 'Search', detail: 'Find relevant knowledge sections' },
    { title: 'Read', detail: 'Read selected sections' }
  ]
}

phase('Search')

const searchResult = await agent(
  `You are executing a semantic search over Nablarch v6 knowledge files.

Query: "入力チェック（バリデーション）の実装方法を教えてください（処理方式: ウェブアプリケーション）（目的: 実装したい）"

Instructions:
1. List all JSON files under /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/ (use Glob tool with pattern "**/*.json")
2. Filter to pages relevant to validation/input-checking for web applications. Look for filenames containing: validation, バリデーション, input, check, form, bean-validation, nablarch-core-validation
3. For each relevant page, read the file and identify sections relevant to the query
4. Return a structured result with selected pages/sections

Return JSON with this structure:
{
  "selected_pages": [{"path": "relative path from knowledge/", "reason": "why selected"}],
  "excluded_pages": [{"path": "relative path from knowledge/", "reason": "why excluded"}],
  "selected_sections": [
    {"file": "full path", "section_id": "sN", "relevance": "high|partial", "reason": "why selected"}
  ],
  "excluded_sections": [
    {"file": "full path", "section_id": "sN", "reason": "why excluded"}
  ]
}`,
  {
    label: 'semantic-search',
    phase: 'Search',
    schema: {
      type: 'object',
      properties: {
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
    }
  }
)

phase('Read')

// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high').slice(0, 10)
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial').slice(0, 10 - highSections.length)
const sectionsToRead = [...highSections, ...partialSections]

const readArgs = sectionsToRead.map(s => {
  // Extract just the filename from the full path
  const parts = s.file.split('/')
  const filename = parts[parts.length - 1]
  return `${filename}:${s.section_id}`
})

log(`Reading ${readArgs.length} sections: ${readArgs.join(', ')}`)

const sectionsContent = await agent(
  `Run this bash command and return its complete output:
bash /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh ${readArgs.map(a => '"' + a + '"').join(' ')}

The script is at /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh
Return the complete raw output.`,
  { label: 'read-sections', phase: 'Read' }
)

return {
  search: searchResult,
  read_args: readArgs,
  sections_content: sectionsContent
}
